import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { useAuth } from "../context/AuthContext";


const Navbar = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const onLogout = () => {
    logout();
    navigate('/');
  };

  const authLinks = (
    <>
      <li><Link to="/dashboard" className="hover:text-green-500">Dashboard</Link></li>
      <li>
        <button onClick={onLogout} className="hover:text-green-500">
          Logout
        </button>
      </li>
    </>
  );

  const guestLinks = (
    <>
      <li><Link to="/login" className="hover:text-green-500">Login</Link></li>
      <li><Link to="/signup" className="bg-green-500 text-white px-4 py-2 rounded-md hover:bg-green-600">Sign Up</Link></li>
    </>
  );

  return (
    <nav className="bg-white shadow-md p-4 mb-8">
      <div className="container mx-auto flex justify-between items-center">
        <h1 className="text-2xl font-bold text-green-600">
          <Link to="/">NutriSync</Link>
        </h1>
        <ul className="flex space-x-6 items-center">
          {user ? authLinks : guestLinks}
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
